/**
 * Генератор названий товаров Moranti.
 *
 * Правила:
 * - Всегда генерирует имя заново (nameAutoGenerated будет true)
 * - Если товар правили руками (nameAutoGenerated = false) — имя не трогаем
 */

const { CATEGORY_RU } = require("./wb-categories");

/**
 * @param {object} opts
 * @param {string} opts.category  — наш slug (crossbody, tote, ...)
 * @param {string} [opts.composition] — материал (натуральная кожа, замша...)
 * @param {string} [opts.wbName] — оригинальное название с WB (для определения мини и т.д.)
 * @returns {string}
 */
function generateName({ category, composition, wbName }) {
  const base = CATEGORY_RU[category] || category;

  // Определяем мини
  const lower = (wbName || "").toLowerCase();
  const isMini =
    lower.includes("мини") ||
    lower.includes("mini");

  // Собираем имя
  let name = isMini ? "Мини " + base : base;

  // Добавляем материал, если он известен
  if (composition) {
    const comp = composition.toLowerCase().trim();
    if (comp === "замша") {
      name = name + " из замши";
    } else if (["натуральная кожа", "кожа", "сафьян", "сафьяновая кожа", "гладкая кожа"].some(
      (k) => comp.includes(k)
    )) {
      name = name + " из натуральной кожи";
    } else if (comp !== "текстиль" && comp !== "полиэстер") {
      name = name + " из " + composition.toLowerCase();
    }
  }

  return name;
}

module.exports = { generateName };
